
import builder from 'tharak-query';
export class BeforeOpr {
    providerId:string;
    constructor(providerId:string){
        this.providerId = providerId;
    }
    intercept(method:string, pConfig:any, input){
        var oquery:any = {};
        if(input.filter)
            oquery.$filter = input.filter;
        if(input.select)
            oquery.$select = input.select;
        if(input.update)
            oquery.$update = input.update;
        if(input.insert)
            oquery.$insert = input.insert;
        var options:any = {dialect: this.providerId};
        if(typeof pConfig.serviceId === 'string')
            options.resource = pConfig.serviceId.trim();
        else{
            options.resource = {name : pConfig.serviceId.body.trim()};
            if(pConfig.serviceId.tag)
                options.resource.alias = pConfig.serviceId.tag;
        }
        let criteria = builder.build(method, oquery, options);
        if(criteria && criteria.filter && pConfig.input && pConfig.input.params){
            let idx=0;
            criteria.filter.forEach((crit:any)=>{
                this.updateRowId(pConfig, crit);
                this.updateObject(pConfig, crit, criteria.filter, idx);
                this.updateArray(pConfig, crit, criteria.filter, idx);
                idx++;
            });
        }
        if(input.select){
            let selects = input.select.split(',');        
            criteria.select = selects;
        }
        return criteria;
    }
    private updateRowId(pConfig:any, crit:any){
        let found = pConfig.input.params.find((param:any)=>param.target === crit.field && param.type === "rowId");
        if(found){
            crit.field = found.type;
        }
    }
    private updateObject(pConfig:any, crit:any, list:any, idx:any){
        let found = pConfig.input.params.find((param:any)=>param.target === crit.field && param.type === "object");
        if(found){            
            list.splice(idx, 1);
            let obj = JSON.parse(crit.value);
            Object.keys(obj).forEach((key:string)=>{
                list.push({field: crit.field+'.'+key, operator: '==', value: obj[key]});
            });
        }
    }
    private updateArray(pConfig:any, crit:any, list:any, idx:any){
        let found = pConfig.input.params.find((param:any)=>param.target === crit.field && param.type === "array");
        if(found){            
            list.splice(idx, 1);
            let array = crit.value;
            if(Array.isArray(array)){
                array.forEach((key:string)=>{
                    list.push({field: crit.field, operator: 'array-contains', value: key});
                });
            }
        }
    }
}
